try { grantFiles = fs.readdirSync(dirPath).filter(function(f) { return f.endsWith('.txt') || f.endsWith('.md'); }); } catch(e) { grantFiles = []; }
if (grantFiles.length === 0) { return [{ json: { fileName: 'No grant files', content: 'No files in /data/Maryland_Grants/', eafProfile, fpProfile, noFiles: true, isPursue: false } }]; }
return grantFiles.map(function(file) { let content = ''; try { content = fs.readFileSync(dirPath + file, 'utf8'); } catch(e) { content = 'Could not read: ' + e.message; } return { json: { fileName: file, content, eafProfile, fpProfile, noFiles: false, isPursue: false } }; });

