If fit 60%+, also draft:
9. LETTER OF INTENT (250-350 words)';
}
// PATCH v3.2: forward missionPath
return [{ json: { systemMessage, userMessage, fileName: input.fileName, isPursue: input.isPursue, task: input.task, entity: input.entity, pipelineId: input.pipelineId, opportunity: input.opportunity, missionPath: input.missionPath || null } }];

