const https = require('https');
const input = $input.first().json;
const requestBody = JSON.stringify({ model: 'claude-sonnet-4-6', max_tokens: 4096, system: input.systemMessage, messages: [{ role: 'user', content: input.userMessage }] });
const options = { hostname: 'api.anthropic.com', port: 443, path: '/v1/messages', method: 'POST', headers: { 'Content-Type': 'application/json', 'x-api-key': $env[

], 'anthropic-version': '2023-06-01', 'Content-Length': Buffer.byteLength(requestBody) } };
const result = await new Promise(function(resolve, reject) { const req = https.request(options, function(res) { let d = ''; res.on('data', function(c) { d += c; }); res.on('end', function() { resolve({ status: res.statusCode, body: d }); }); }); req.on('error', reject); req.write(requestBody); req.end(); });
let aiOutput = '';
try { aiOutput = JSON.parse(result.body).content[0].text || 'No response.'; } catch(e) { aiOutput = result.body.substring(0, 500); }
// PATCH v3.2: forward missionPath
return [{ json: { aiOutput, fileName: input.fileName, isPursue: input.isPursue, task: input.task, entity: input.entity, pipelineId: input.pipelineId, opportunity: input.opportunity, missionPath: input.missionPath || null, status: result.status } }];

const fs = require('fs');
const crypto = require('crypto');
const input = $input.first().json;
const aiOutput = input.aiOutput;
const fileName = input.fileName;
const isPursue = input.isPursue || false;
const timestamp = new Date().toISOString();
let safeName = '';
for (let i = 0; i < fileName.length; i++) { const code = fileName.charCodeAt(i); if ((code >= 65 && code <= 90) || (code >= 97 && code <= 122) || (code >= 48 && code <= 57)) { safeName += fileName[i]; } else { safeName += '_'; } }
const safeTime = timestamp.split(':').join('-').split('.').join('-');
const subdir = isPursue ? 'Pipeline' : 'Grant_Report';
const outputPath = '/data/Aidan_Outputs/Jordan/' + subdir + '_' + safeTime + '_' + safeName + '.txt';
fs.mkdirSync('/data/Aidan_Outputs/Jordan', { recursive: true });
const header = isPursue ? 'JORDAN PIPELINE DRAFT v3.2\nOpportunity: ' + (input.opportunity || fileName) + '\nTask: ' + (input.task || 'loi') + '\nEntity: ' + (input.entity || 'EAF') + '\nPipeline ID: ' + (input.pipelineId || 'N/A') + '\nGenerated: ' + timestamp + '\n\n' : 'JORDAN GRANT REPORT v3\nFile: ' + fileName + '\nGenerated: ' + timestamp + '\n\n';
fs.writeFileSync(outputPath, header + aiOutput, 'utf8');
let fitScore = null; let funder = 'See report'; let action = isPursue ? 'PURSUING' : 'Review report'; let deadline = null;
const lines = aiOutput.split('\n');
for (let i = 0; i < lines.length; i++) { const line = lines[i]; if (!isPursue && line.toUpperCase().indexOf('FIT SCORE') !== -1) { const nums = line.match(/\d+/); if (nums) fitScore = parseInt(nums[0]); } if (line.toUpperCase().indexOf('FUNDER') !== -1 && line.indexOf(':') !== -1) { funder = line.split(':').slice(1).join(':').trim().replace(/\*/g,'').substring(0,60); } if (!isPursue && line.toUpperCase().indexOf('RECOMMENDED ACTION') !== -1 && line.indexOf(':') !== -1) { action = line.split(':').slice(1).join(':').trim().replace(/\*/g,''); } if (line.toUpperCase().indexOf('DEADLINE') !== -1 && line.indexOf(':') !== -1) { deadline = line.split(':').slice(1).join(':').trim().replace(/\*/g,'').substring(0,50); } }
const fitScoreDisplay = fitScore !== null ? fitScore + '%' : (isPursue ? 'N/A (pursue)' : 'See report');
const loiDrafted = isPursue || aiOutput.toLowerCase().indexOf('letter of intent') !== -1;
let summary;
if (isPursue) { const taskLabel = { 'loi': 'LOI', 'capability_statement': 'Capability Statement', 'sbir_narrative': 'SBIR Narrative', 'capability_statement_and_loi': 'Cap Stat + LOI' }[input.task] || 'Draft'; summary = 'JORDAN ' + taskLabel + ' COMPLETE\nOpportunity: ' + (input.opportunity || fileName) + '\nEntity: ' + (input.entity || 'EAF') + '\nSaved: ' + outputPath; } else { summary = 'JORDAN GRANT ANALYSIS COMPLETE\nGrant: ' + fileName + '\nFunder: ' + funder + '\nFit Score: ' + fitScoreDisplay + '\nDeadline: ' + (deadline || 'UNCONFIRMED') + '\nAction: ' + action + '\nLOI Drafted: ' + (loiDrafted ? 'YES' : 'NO (fit below threshold)') + '\nReport: ' + outputPath; }
const contentHash = crypto.createHash('md5').update(fileName + new Date().toISOString().slice(0,10)).digest('hex');
// PATCH v3.2: forward missionPath
return [{ json: { summary, outputPath, fileName, fitScore, fitScoreDisplay, funder, action, deadline, loiDrafted, aiOutput, timestamp, contentHash, isPursue, entity: input.entity, pipelineId: input.pipelineId, task: input.task, opportunity: input.opportunity, missionPath: input.missionPath || null } }];

const https = require('https');
const input = $input.first().json;
const SUPABASE_URL = $env.SUPABASE_URL || '';
const SUPABASE_KEY = $env.SUPABASE_SERVICE_KEY || '';
const hostname = SUPABASE_URL.replace('https://', '').replace('http://', '');
let actionCode = null;
if (input.action) { const a = input.action.toUpperCase(); if (a.indexOf('APPLY') !== -1) actionCode = 'APPLY'; else if (a.indexOf('PASS') !== -1) actionCode = 'PASS'; else if (a.indexOf('WATCH') !== -1) actionCode = 'WATCH'; else if (a.indexOf('PURSUING') !== -1) actionCode = 'PURSUING'; }
const record = { grant_file: input.fileName, funder: input.funder !== 'See report' ? input.funder : null, fit_score: input.fitScore || null, recommended_action: actionCode, loi_drafted: input.loiDrafted || false, jordan_report_path: input.outputPath, application_status: input.isPursue ? 'pursuing' : 'analyzing', entity: input.entity || 'EAF' };
try { const body = JSON.stringify(record); const result = await new Promise(function(resolve, reject) { const req = https.request({ hostname, port: 443, path: '/rest/v1/grant_applications', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': SUPABASE_KEY, 'Authorization': 'Bearer ' + SUPABASE_KEY, 'Prefer': 'resolution=merge-duplicates', 'Content-Length': Buffer.byteLength(body) } }, function(res) { let d = ''; res.on('data', function(c) { d += c; }); res.on('end', function() { resolve({ status: res.statusCode, body: d }); }); }); req.on('error', reject); req.write(body); req.end(); }); const out = Object.assign({}, input); out.supabaseLogged = result.status === 201 || result.status === 200; out.supabaseStatus = result.status; return [{ json: out }]; } catch(e) { const out = Object.assign({}, input); out.supabaseLogged = false; out.supabaseError = e.message; return [{ json: out }]; }

// JORDAN AIDAN CALLBACK v3.2 â€” PATCH: mission chain writeback via /mission/update
const http = require('http');
const input = $input.first().json;
const supabaseLogged = input.supabaseLogged || false;
const outputPath = input.outputPath || '';
const missionPath = input.missionPath || null;

// â”€â”€ Mission chain writeback (fire-and-forget) â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
let chainUpdate = { ok: false, reason: 'no mission_path' };
if (missionPath) {
  const updateBody = JSON.stringify({
    path: missionPath,
    updates: {
      status: 'IN_PROGRESS',
      next_agent: 'Aidan',
      execution_chain: {
        nova_plan: 'COMPLETE',
        jordan_draft: 'COMPLETE',
      },
    },
    event: {
      agent: 'Jordan',
      action: 'JORDAN_DRAFT_COMPLETE',
      note: 'Draft complete. File: ' + outputPath + ' | Task: ' + (input.task || 'unknown') + ' | LOI: ' + (input.loiDrafted ? 'YES' : 'NO'),
    },
  });
  try {
    const updateResult = await new Promise(function(resolve) {
      const req = http.request(
        { hostname: '127.0.0.1', port: 3030, path: '/mission/update', method: 'POST',
          headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(updateBody) } },
        function(res) {
          let d = '';
          res.on('data', function(c) { d += c; });
          res.on('end', function() {
            try { resolve({ ok: res.statusCode === 200, body: JSON.parse(d) }); }
            catch(e) { resolve({ ok: false, raw: d }); }
          });
        }
      );
      req.on('error', function(e) { resolve({ ok: false, reason: e.message }); });
      req.setTimeout(5000, function() { req.destroy(); resolve({ ok: false, reason: 'timeout' }); });
      req.write(updateBody);
      req.end();
    });
    chainUpdate = updateResult;
  } catch(e) {
    chainUpdate = { ok: false, reason: e.message };
  }
}

const dbStatus = supabaseLogged ? 'Logged to Supabase' : 'Supabase log skipped';
const chainStatus = chainUpdate.ok
  ? 'Mission chain: UPDATED (jordan_draft=COMPLETE, next=Aidan)'
  : 'Mission chain: ' + (missionPath ? 'UPDATE FAILED â€” ' + (chainUpdate.reason || 'see logs') : 'NO PATH (grant-reader mode)');

let msgText;
if (input.isPursue && input.aiOutput) {
  msgText = 'JORDAN PIPELINE DRAFT COMPLETE\nOpportunity: ' + (input.opportunity || input.fileName) + '\nTask: ' + (input.task || 'LOI') + '\nEntity: ' + (input.entity || 'EAF') + '\n' + chainStatus + '\nFull draft emailed to kas@kevin-llc.com\nSaved: ' + outputPath + '\n\n--- DRAFT PREVIEW ---\n' + input.aiOutput.substring(0, 2400) + (input.aiOutput.length > 2400 ? '\n\n[Continued in email]' : '');
} else {
  msgText = 'JORDAN GRANT ANALYSIS COMPLETE\nGrant: ' + (input.opportunity || input.fileName) + '\nFunder: ' + (input.funder || 'See report') + '\nFit Score: ' + (input.fitScoreDisplay || 'See report') + '\nDeadline: ' + (input.deadline || 'UNCONFIRMED') + '\nAction: ' + (input.action || 'WATCH') + '\nLOI Drafted: ' + (input.loiDrafted ? 'YES' : 'NO (fit below threshold)') + '\nReport: ' + outputPath + '\n' + dbStatus;
}

const chunks = [];
for (let i = 0; i < msgText.length; i += 3800) chunks.push(msgText.substring(i, i + 3800));
for (let i = 0; i < chunks.length; i++) {
  const mb = JSON.stringify({ number: '14432576836@s.whatsapp.net', textMessage: { text: chunks[i] } });
  const opts = { hostname: 'host.docker.internal', port: 8081, path: '/message/sendText/Aidan', method: 'POST', headers: { 'Content-Type': 'application/json', 'apikey': 'Kevin2026', 'Content-Length': Buffer.byteLength(mb) } };
  await new Promise(function(r) { const req = http.request(opts, function(res) { res.on('data', function() {}); res.on('end', r); }); req.on('error', r); req.write(mb); req.end(); });
  if (chunks.length > 1) await new Promise(function(r) { setTimeout(r, 1200); });
}

const cbBody = JSON.stringify({
  agent: 'Jordan', version: 'v3.2',
  summary: input.summary || 'Jordan complete.',
  fitScore: input.fitScoreDisplay,
  fileName: input.fileName,
  isPursue: input.isPursue,
  supabaseLogged,
  missionChainUpdated: chainUpdate.ok,
  missionPath,
  timestamp: new Date().toISOString()
});
const cbOpts = { hostname: 'host.docker.internal', port: 5678, path: '/webhook/aidan-callback', method: 'POST', headers: { 'Content-Type': 'application/json', 'Content-Length': Buffer.byteLength(cbBody) } };
const cbReq = http.request(cbOpts, function(res) { res.on('data', function() {}); res.on('end', function() {}); });
cbReq.on('error', function() {});
cbReq.write(cbBody);
cbReq.end();

return [{ json: { success: true, agent: 'Jordan', version: 'v3.2', summary: input.summary, supabaseLogged, missionChainUpdated: chainUpdate.ok } }];
